module multi_16bit
(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output yout,
    output done
);

    reg [4:0] i;
    reg [31:0] areg;
    reg [31:0] breg;
    reg [31:0] yout_r;
    reg done_r;
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            i <= 5'b0;
        end
        else if(start && i < 5'd17) begin
            i <= i + 5'b1;
        end
        else if(!start) begin
            i <= 5'b0;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            done_r <= 1'b0;
        end
        else if(i == 5'd16) begin
            done_r <= 1'b1;
        end
        else if(i == 5'd17) begin
            done_r <= 1'b0;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            areg <= 32'b0;
            breg <= 32'b0;
            yout_r <= 32'b0;
        end
        else if(start) begin
            if(i == 5'd0) begin
                areg <= {16'b0, ain};
                breg <= {16'b0, bin};
            end
            else if(i > 5'd0 && i < 5'd17) begin
                if(areg[i-1]) begin
                    yout_r <= (yout_r + (breg << (i-1))) << 1 | 1'b0;
                end
                else begin
                    yout_r <= yout_r << 1 | 1'b0;
                end
            end
        end
    end
    assign done = done_r;
    assign yout = yout_r;

endmodule
